        z3 = abs(z3);
        z3 -= 2.0 * min(0.0, dot(z3, uCox_nc)) * uCox_nc;
        z3 = abs(z3);
        z3 -= 2.0 * min(0.0, dot(z3, uCox_nc)) * uCox_nc;
        z3 = abs(z3);
        z3 -= 2.0 * min(0.0, dot(z3, uCox_nc)) * uCox_nc;
        z3 = abs(z3);
        z3 -= 2.0 * min(0.0, dot(z3, uCox_nc)) * uCox_nc;

